SELECT count(*) FROM kind_type, title, movie_info, cast_info, role_type, info_type, movie_companies WHERE title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND movie_info.info_type_id = info_type.id AND movie_companies.movie_id = title.id;